// 提示
<template>
<div class="tips" v-if="text">
  <div class="t" v-if="!isShow">
    <div class="text" v-if="t1">！本篇内容来源于网络，暂未测试</div>
    <div class="text" v-if="t2">！使用第三方库时，请注意二次封装</div>
  </div>

  <div class="text" v-if="isShow">！{{ text }}</div>

  <div class="bgc" />
</div>
</template>

<script>
export default {
  props: {
    text: String,
  },
  computed: {
    // 是否显示默认提示
    isShow() {
      // 如果传入了值，且值不是默认值 -1、-2 则显示值
      if(this.text != undefined
      && this.text != '-1'
      && this.text != '-2') {
        return true
      } else {
        return false
      }
    },
    t1() {
      // 如果传入的值是默认值 -1
      if(this.text === '-1') {
        // 显示提示1
        return true
      } else {
        return false
      }
    },
    t2() {
      // 如果传入的值是默认值 -2
      if(this.text === '-2') {
        // 显示提示2
        return true
      } else {
        return false
      }
    }
  }
}
</script>

