<template>
  <div class="cont-template" :style="opacity">
    <doc-title :text="title" />
    <tips :text="tips" />

    <div class="message">
      <paragraph v-for="(item, i) in message" :key="i" :message="item" :identifier="item.identifier" />
    </div>

    <Copyright :color="'hei'" />
  </div>
</template>

<script>
import tips from 'common/paragraph/tips.vue' // 警告
import Copyright from 'common/Copyright.vue' // 版权

export default {
  name: 'cont-template',
  activated() {
    // console.log("跳")
    // 进入缓存，必定是异界面（不同路由）
    // 生命周期出现 bug：其他页面触发本页面进入/离开生命周期。使用地址检测规避 bug
    if(this.$route.path.search("/study/") == 0) {
      document.getElementById(this.$store.state.lv4_id).scrollIntoView()

      this.tiemr = setTimeout(() => {
        this.opacity = {
          opacity: 1,
          transition: 'all .22s'
        }
      }, 120)
    }

    this.$store.commit("git_lv4_id", "id-top")
  },
  deactivated() {
    // console.log("走")
    // 取消定时器
    clearTimeout(this.timer);

    this.opacity = {
      opacity: 0,
      transition: 0
    }
  },
  data() {
    return {
      timer: -1,
      opacity: {}
    }
  },
  props: {
    tips: String,
    title: String,
    message: Object
  },
  components: {
    tips,
    Copyright
  },
}
</script>

<style lang="less" scoped>
.cont-template {
  opacity: 0;
  position: relative;
}
</style>